import test from "node:test";
import assert from "node:assert/strict";
import { RetryBudget } from "../src/budget.mjs";
import { scheduleRetry } from "../src/scheduler.mjs";

test("numeric backoff is clipped to the remaining scheduling budget", () => {
  const origin = 1_900_000_000_000;
  const queue = [];
  const budget = new RetryBudget(2_500);
  const scheduled = scheduleRetry({
    retryAfter: "9",
    nowMs: origin,
    budget,
    enqueue: (time) => queue.push(time),
  });

  assert.strictEqual(scheduled, origin + 2_500, "wrong queue deadline");
  assert.deepStrictEqual(queue, [origin + 2_500], "queue received wrong time");
  assert.strictEqual(budget.usedMs, 2_500, "budget accounting drifted");
});
